#!/usr/bin/perl

use CGI qw(:standard);
use CGI::Carp qw(warningsToBrowser fatalsToBrowser);

my $q = new CGI;
my $logfile = $q->param('logfile');
my $log_dir = "/path/to/log/directory";

print $q->header();
print $q->start_html('Log Viewer');

if (defined $logfile) {

    if (open(FH, "$log_dir/$logfile")) {
        print "<h1>Viewing log file: $logfile</h1><pre>\n";
        
        while (<FH>) {
            chomp;
            print $_."<br>\n";
        }
        print "</pre>\n";
        close(FH);

    } else {
        print "<h1>Error:</h1><p>Could not open log file $logfile: $!</p>";
    }
} 
else {
    print "<h1>Error:</h1> <p>No log file specified!</p>";
}

print $q->end_html();